docs/next/lit/FUSE.sources.jsonl:7:{"id": "kblam-2025", "title": "KBLaM: Knowledge Base augmented Language Model", "venue": "ICLR 2025", "year": 2025, "url": "https://proceedings.iclr.cc/paper_files/paper/2025/hash/803485352e61e3ebf41221e4776c9fd4-Abstract-Conference.html", "claim": "MECHANISM/SCALING (primary-verified): KB triples -> continuous KV pairs via pre-trained sentence encoder + trained linear adapters, read through rectangular attention; overhead linear in KB size (vs quadratic for in-context); >10K triples into an 8B LLM with 8K window on one A100 80GB; dynamic KB updates without retraining; retrieval-free; interpretable attention. LIMITATIONS (secondary-only, UNVERIFIED): precision-decay-with-KB-size / refusal drift, OOD (Enron) degradation, and rewording drift are restated from uncited secondary sources (repo documentation, reviews) and were NOT re-verified in the paper body — direction-only, do not build on specifics.", "fetched": "2026-07-11", "bib_verified": true, "venue_verified": true, "claims_verified": "mixed — mechanism/scaling primary (proceedings abstract page); limitation claims secondary-only, UNVERIFIED", "anchor": "ICLR proceedings abstract page (mechanism claims); limitations have NO primary anchor"}
