docs/next/lit/RULE.sources.jsonl:13:{"id":"kblam-2025","title":"KBLaM: Knowledge Base augmented Language Model","venue":"ICLR (venue per prior verified review 2026-07-08; arXiv page fetched today)","year":2025,"url":"https://arxiv.org/abs/2410.10450","claim":"KB triples -> continuous KV 'knowledge tokens' via pre-trained sentence encoders + trained linear adapters, read through rectangular attention; >10K triples into an 8B host, one A100, linear scaling in KB size; instruction-tunes the projection, base weights untouched; claims attention weights give 'interpretable insights' into knowledge use.","verified":true}
docs/next/lit/RULE.sources.jsonl:16:{"id":"memory-layers-2024","title":"Memory Layers at Scale","venue":"arXiv (Meta)","year":2024,"url":"https://arxiv.org/abs/2412.09764","claim":"Trainable sparsely-activated KV memory layers complementing dense FFN: models beat dense baselines with >2x the compute budget, and beat MoE at matched compute AND params; up to 128B memory params, 1T tokens, base models to 8B; gains concentrated on factual tasks. Honest accounting: params up, FLOPs matched — a trained-from-pretraining architecture, not a bolt-on store.","verified":true}
docs/next/lit/RULE.sources.jsonl:17:{"id":"cache-steering-2025","title":"KV Cache Steering for Controlling Frozen LLMs (v1: KV Cache Steering for Inducing Reasoning in Small Language Models)","venue":"arXiv","year":2025,"url":"https://arxiv.org/abs/2507.08799","claim":"Training-free ONE-SHOT intervention on the KV cache (vectors distilled from GPT-4o reasoning traces) induces explicit multi-step reasoning in small models (SmolLM2-360M-class per paper experiments) and transfers reasoning styles; more stable to hyperparameters and cheaper than continuous activation steering. Behaviour-level, not content-level, KV write at our band.","verified":true}
