docs/next/lit/RULE.sources.jsonl:36:{"id":"axbench-2025","title":"AxBench: Steering LLMs? Even Simple Baselines Outperform Sparse Autoencoders","venue":"ICML (per proceedings; arXiv page fetched)","year":2025,"url":"https://arxiv.org/abs/2501.17148","claim":"On Gemma-2-2B/9B concept steering: PROMPTING outperforms all representation methods, finetuning second; SAEs not competitive; difference-in-means best for detection. The matched-baseline discipline result for the whole steering family.","verified":true}
docs/next/lit/RULE.sources.jsonl:39:{"id":"vsa-rule-2025","title":"Improving Rule-based Reasoning in LLMs using Neurosymbolic Representations","venue":"EMNLP 2025 main (pp. 30589-30608, doi 10.18653/v1/2025.emnlp-main.1556)","year":2025,"url":"https://aclanthology.org/2025.emnlp-main.1556/","claim":"Encode hidden states into VSA vectors, run symbolic algorithms in vector space, decode and merge back: 88.6% lower cross-entropy and 15.4x more math problems solved vs CoT and supervised-fine-tuning/LoRA baselines while retaining other-benchmark performance. Single-group, narrow task suite; the direct H-RULE-ACT prior (and the nsk1-adjacent design).","locator":"ACL Anthology abstract (immutable proceedings record; figures 88.6%/15.4x confirmed there 2026-07-11). Pinned to the Anthology because the arXiv 2502.01657 page is mutable and its current abstract reports different numbers.","verified":true}
