docs/next/lit/RULE.sources.jsonl:47:{"id":"prag-2026","title":"Understanding Parametric Knowledge Injection in Retrieval-Augmented Generation (v2 title; v1 was titled 'The Role of Parametric Injection-A Systematic Study of Parametric Retrieval-Augmented Generation')","venue":"arXiv","year":2026,"url":"https://arxiv.org/abs/2510.12668v2","claim":"LoRA-encoded documents (P-RAG) capture document-level semantics in deep FFN computation, give high-level guidance but LIMITED evidence consolidation; parametric alone does not consistently outperform token-level RAG — hybrid PT-RAG wins.","locator":"Version-pinned to v2 (paper retitled between v1 and v2; both titles recorded above; v1/v2 titles confirmed at arXiv 2026-07-11).","verified":true}
