docs/next/lit/STORE.sources.jsonl:10:{"id": "pellissier-tanon-freebase-wikidata-www-2016", "title": "From Freebase to Wikidata: The Great Migration", "author": "Pellissier Tanon T, Vrandecic D, Schaffert S, Steiner T, Pintscher L", "venue": "WWW 2016 (25th Int. Conf. on World Wide Web)", "year": 2016, "url": "https://dl.acm.org/doi/10.1145/2872427.2874809", "doi": "10.1145/2872427.2874809", "claim": "Abstract states: 'Due to the success of Wikidata, Google decided in 2014 to offer the content of Freebase to the Wikidata community.' Google's bulk export mapped ~4.6M Freebase topics to Wikidata and generated ~14M candidate statements; migration ran through the open-source Primary Sources Tool where, by Jan 2016, 100+ users had performed ~90,000 approval/rejection actions -- only a small fraction of the candidate statements. Every migrated statement required manual human review.", "verified": true, "verification": "Venue/DOI confirmed; abstract fetched 2026-07-11 (rationale = 'success of Wikidata'). Figures (4.6M topics, 14M statements, ~90,000 actions, 100+ users, Jan 2016) from the Google-archived copy summary + corroborating sources; full text NOT parsed. REVISION 2026-07-11b: 'provenance verification was THE bottleneck' downgraded to an inference -- the paper reports the per-statement review effort and its slow throughput, not a stated 'bottleneck' verdict or a measured labour cost. The ~90,000 actions cover only a small fraction of the 14M candidates."}
docs/next/lit/STORE.sources.jsonl:12:{"id": "vu-freshllms-acl-2024", "title": "FreshLLMs: Refreshing Large Language Models with Search Engine Augmentation", "author": "Vu T, Iyyer M, Wang X, et al.", "venue": "Findings of ACL 2024", "year": 2024, "url": "https://aclanthology.org/2024.findings-acl.813/", "claim": "FreshQA (600 QA pairs requiring fast-changing world knowledge) shows all LLMs struggle on questions needing up-to-date knowledge and produce outdated answers; static parametric knowledge goes stale, and search-augmentation (FreshPrompt) is needed to refresh it. Direct evidence that fact staleness is a first-order, recurring cost.", "verified": true, "verification": "ACL Anthology listing confirmed (2024.findings-acl.813); arXiv 2310.03214. Claim from abstract/benchmark description."}
docs/next/lit/STORE.sources.jsonl:16:{"id": "paulheim-kg-refinement-semweb-2017", "title": "Knowledge Graph Refinement: A Survey of Approaches and Evaluation Methods", "author": "Heiko Paulheim", "venue": "Semantic Web 8(3):489-508", "year": 2017, "url": "https://journals.sagepub.com/doi/full/10.3233/SW-160218", "doi": "10.3233/SW-160218", "claim": "Large-scale KGs (DBpedia, YAGO, NELL, Freebase, Google KG) make an explicit trade-off between completeness and correctness; automatic construction leaves errors and gaps that require a continuous refinement/correction stage (error detection + completion) evaluated by precision/recall/AUC. Maintenance is a standing, never-finished cost, not a one-time build.", "verified": true, "verification": "Venue/DOI/pages confirmed via IOS Press Semantic Web + dblp; thesis from abstract/survey scope."}
