docs/next/lit/SYS.sources.jsonl:4:{"id":"mlperf-power-2410.12032","title":"MLPerf Power: Benchmarking the Energy Efficiency of Machine Learning Systems from Microwatts to Megawatts","venue":"arXiv (v2 2025; Tschand et al.)","year":2024,"url":"https://arxiv.org/html/2410.12032v2","locator":"methodology sections of the v2 HTML full text","claim":"Full-system wall power as fundamental tenet; SPEC-certified analyzers (Yokogawa WT310) + PTDaemon; range-fixing calibration run then fixed analyzer ranges; >=60 s power data; energy by integrating samples over run window; Samples/Joule; datacenter boundary includes compute+interconnect, excludes cooling/storage nodes; 1,841 measurements across 60 systems; TDP is thermal limit not power proxy; cloud granularity pitfall","verified":true}
docs/next/lit/SYS.sources.jsonl:5:{"id":"sardana-2401.00448","title":"Beyond Chinchilla-Optimal: Accounting for Inference in Language Model Scaling Laws","venue":"ICML","year":2024,"url":"https://arxiv.org/abs/2401.00448","locator":"v2 HTML full text incl. worked examples and limitations","claim":"30B-quality @1e13 inference tokens -> 13.6B on 2.84x data, -28% total FLOPs; real-cost @1.5B requests -> 16B on 3.35T tokens, ~17% cost saving; 13B-quality @2T tokens -> 7B, -17% FLOPs; Chinchilla-70B @2T tokens: +1.3% FLOPs but 36% cost gap (inference ~1% MFU on output tokens vs ~50% training MFU); 47 models 150M-6B at 10-10,000 tokens/param; loss does not plateau at 10,000 t/p for 150M; Chinchilla fits on typical ratios overestimate extra-token value at extreme ratios. STATED LIMITS carried: the dollar model is explicitly simplified (fixed utilisation, no maintenance/refresh/demand-uncertainty); extreme-ratio scaling fits misbehave (authors refit); quality axis is pretraining loss, not a capability index — licenses the qualitative demand-changes-optimal-size proposition plus its own worked numbers under its own assumptions, nothing stronger","verified":true}
