docs/next/lit/NTP.sources.jsonl:20:{"id":"dilp-2018","title":"Learning Explanatory Rules from Noisy Data (dILP)","venue":"JAIR","year":2018,"url":"https://arxiv.org/abs/1711.04574","claim":"Differentiable ILP robust to noise/ambiguity unlike classical ILP; explicitly memory-bound - bounded predicate counts and rule templates limit it to small domains. Rule LEARNING at kernel-rule scale is feasible; rule REASONING at KB scale is not, in this family.","verified":true}
docs/next/lit/NTP.sources.jsonl:21:{"id":"deepproblog-2018","title":"DeepProbLog: Neural Probabilistic Logic Programming","venue":"NeurIPS (spotlight)","year":2018,"url":"https://arxiv.org/abs/1805.10872","claim":"Neural predicates inside ProbLog with exact probabilistic inference in the training objective (executor-in-the-loss, module scale: MNIST-addition-class tasks); the canonical probabilistic-logic-in-the-loss system; exact WMC inference cost is the known scaling ceiling (successors Scallop/A-NESI exist to approximate it).","verified":true}
docs/next/lit/NTP.sources.jsonl:22:{"id":"scallop-2023","title":"Scallop: A Language for Neurosymbolic Programming","venue":"PLDI 2023 [memory]; arXiv abs page shows cs.PL only","year":2023,"url":"https://arxiv.org/abs/2304.04812","claim":"Datalog + provenance semirings for tunable approximate differentiable reasoning (top-k proofs); across 8 neurosymbolic apps: comparable-or-better accuracy than SOTA neural models with better runtime/data-efficiency/interpretability - module/app scale, not LM-scale, and 'comparable-or-superior' is the honest summary, not dominance.","verified":true}
docs/next/lit/NTP.sources.jsonl:23:{"id":"semantic-loss-2018","title":"A Semantic Loss Function for Deep Learning with Symbolic Knowledge","venue":"ICML","year":2018,"url":"https://arxiv.org/abs/1711.11157","claim":"Compile logical constraints (via circuits) into a differentiable loss bridging network outputs and symbolic specs; wins in semi-supervised classification + structured outputs (rankings, paths). The clean 'constraint-executor in the LOSS' primitive - proven at output-layer/module scale only.","verified":true}
docs/next/lit/NTP.sources.jsonl:27:{"id":"transnar-2024","title":"Transformers meet Neural Algorithmic Reasoners (TransNAR)","venue":"CVPR 2024 Multimodal Algorithmic Reasoning Workshop","year":2024,"url":"https://arxiv.org/abs/2406.09308","claim":"LM tokens cross-attend to a pretrained NAR's node embeddings; significant in- and out-of-distribution gains over Transformer-only on CLRS-Text. Abstract does not state parameter/compute-matching of the baseline nor the '20% absolute' magnitude (UNVERIFIED at that precision); requires the graph input at inference - a fusion prior-art datapoint for P3-LR-FUSE more than a deployable recipe.","verified":true}
docs/next/lit/NTP.sources.jsonl:29:{"id":"discrete-nar-2025","title":"Discrete Neural Algorithmic Reasoning","venue":"ICML","year":2025,"url":"https://arxiv.org/abs/2402.11628","claim":"Forcing execution trajectories into finite predefined discrete states (separating discrete/continuous flows) yields PERFECT test scores incl. OOD in single- and multi-task setups, with correctness provable on any test data - the strongest published support for 'hard symbolic interface at step 0 buys OOD transfer', on covered algorithmic tasks with state supervision.","verified":true}
docs/next/lit/NTP.sources.jsonl:33:{"id":"ruletaker-2020","title":"Transformers as Soft Reasoners over Language (RuleTaker)","venue":"IJCAI","year":2020,"url":"https://arxiv.org/abs/2002.05867","claim":"Transformers trained on NL rule theories reach 99% in-distribution on deduction, 95%+ on depths beyond training, and transfer zero-shot to hand-authored and paraphrased rulebases - bounded-depth closed-world deduction over stated rules is learnable at ~350M scale.","verified":true}
