docs/next/lit/NTP.sources.jsonl:49:{"id":"satnet-debunk-2020","title":"Assessing SATNet's Ability to Solve the Symbol Grounding Problem","venue":"NeurIPS","year":2020,"url":"https://proceedings.neurips.cc/paper/2020/hash/0ff8033cf9437c213ee13937b1c4c455-Abstract.html","claim":"Without leaked intermediate symbol labels, visual SATNet drops to 0% test accuracy - the differentiable-logic layer never solved symbol grounding; naive SATNet on an MNIST grounding sanity check is worse than logic-free models. Carried: search-snippet quoting the NeurIPS abstract this pass + prior verification in the parsing report; proceedings page itself not fetched - UNVERIFIED-THIS-PASS at page level.","verified":false}
