docs/next/lit/NTP.sources.jsonl:54:{"id":"faith-fate-2023","title":"Faith and Fate: Limits of Transformers on Compositionality","venue":"NeurIPS 2023 [memory]; arXiv abs page shows no venue","year":2023,"url":"https://arxiv.org/abs/2305.18654","claim":"On multi-digit multiplication, logic-grid puzzles, and dynamic programming, transformers - INCLUDING models trained/finetuned on explicit step-by-step reasoning traces - solve compositional tasks by linearized subgraph matching (pattern reuse), not systematic procedure induction, and fail as complexity grows or OOD. Third independent negative line (with paradox-2022, prontoqa-2023) against trace-distillation-without-executor.","verified":true}
docs/next/lit/RAG.sources.jsonl:1:{"id": "snell-ttc-2025", "title": "Scaling LLM Test-Time Compute Optimally Can be More Effective than Scaling Parameters for Reasoning", "venue": "ICLR 2025 (oral)", "year": 2025, "url": "https://proceedings.iclr.cc/paper_files/paper/2025/hash/1b623663fd9b874366f3ce019fdfdd44-Abstract-Conference.html", "claim": "Difficulty-adaptive compute-optimal test-time scaling improves efficiency >4x over best-of-N; in a separate FLOPs-matched comparison, a smaller model with test-time compute outperforms a 14x larger model on prompts where the base model has non-trivial success rate. Envelope: PaLM-2-class models on MATH with fine-tuned revision models and PRMs; difficulty estimation itself costs test-time compute; the two findings are separate comparisons, not one exchange rate; generalisation beyond math/easily-verified domains left unresolved by the authors; 14x depends on difficulty and assumed inference-to-pretraining ratio.", "verified": true}
